   111→    document.addEventListener('DOMContentLoaded', async () => {
   112→      const user = await checkAuth();
   113→      if (!user) {
   114→        window.location.href = '/login.html';
   115→        return;
   116→      }
   117→      // Verify recruiter/employer role - must have company_id and appropriate role
   118→      const allowedRoles = ['employer', 'recruiter', 'hiring_manager', 'admin'];
   119→      if (!user.company_id || !allowedRoles.includes(user.role)) {
   120→        window.location.href = '/candidate-dashboard.html';
   121→        return;
   122→      }
   123→
   124→      const name = user.name || user.email.split('@')[0];
   125→      document.getElementById('user-name').textContent = name;
   126→      document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
   127→      document.getElementById('company-name').textContent = user.company_name || 'Company';
   128→
   129→      loadJobs();
   130→
   131→      // Filter tabs
   132→      document.querySelectorAll('.filter-tab').forEach(tab => {
   133→        tab.addEventListener('click', () => {
   134→          document.querySelectorAll('.filter-tab').forEach(t => t.classList.remove('active'));
   135→          tab.classList.add('active');
   136→          currentFilter = tab.dataset.status;
   137→          loadJobs();
   138→        });
   139→      });
   140→    });
   141→
   142→    async function loadJobs() {
   143→      try {
   144→        const url = currentFilter === 'all' ? '/recruiter/jobs' : `/recruiter/jobs?status=${currentFilter}`;
   145→        const data = await apiCall(url);
   146→        if (!data) return;
   147→
   148→        renderJobs(data.jobs || []);
   149→      } catch (err) {
   150→        console.error('Failed to load jobs:', err);
   151→      }
   152→    }
   153→
   154→    function renderJobs(jobs) {
   155→      const container = document.getElementById('jobs-list');
   156→
   157→      if (jobs.length === 0) {
   158→        container.innerHTML = `
   159→          <div class="empty-state">
   160→            <div class="empty-icon">💼</div>
   161→            <h3>No jobs found</h3>
   162→            <p>Create your first job posting to start receiving applications.</p>
   163→            <a href="/job-create.html" class="btn btn-primary">Post New Job</a>
   164→          </div>
   165→        `;
   166→        return;
   167→      }
   168→
   169→      container.innerHTML = jobs.map(job => `
   170→        <div class="job-card">
   171→          <div class="job-header">
   172→            <div class="job-title-row">
   173→              <h3>${job.title}</h3>
   174→              <span class="status-badge ${job.status}">${job.status}</span>
   175→            </div>
   176→            <div class="job-meta">
   177→              ${job.location ? `<span>📍 ${job.location}</span>` : ''}
   178→              ${job.salary_range ? `<span>💰 ${job.salary_range}</span>` : ''}
   179→              <span>📅 ${new Date(job.created_at).toLocaleDateString()}</span>
   180→            </div>
   181→          </div>
   182→
   183→          <div class="job-stats">
   184→            <div class="job-stat">
   185→              <span class="stat-value">${job.views || 0}</span>
   186→              <span class="stat-label">Views</span>
   187→            </div>
   188→            <div class="job-stat">
   189→              <span class="stat-value">${job.application_count || 0}</span>
   190→              <span class="stat-label">Applications</span>
   191→            </div>
   192→            <div class="job-stat">
   193→              <span class="stat-value">${job.interviews || 0}</span>
   194→              <span class="stat-label">Interviews</span>
   195→            </div>
   196→          </div>
   197→
   198→          <div class="job-actions">
   199→            <a href="/recruiter-applications.html?job_id=${job.id}" class="btn btn-ghost btn-sm">View Applications</a>
   200→            <button class="btn btn-ghost btn-sm" onclick="toggleJobStatus(${job.id}, '${job.status}')">
   201→              ${job.status === 'active' ? 'Pause' : 'Activate'}
   202→            </button>
   203→            <button class="btn btn-ghost btn-sm" onclick="editJob(${job.id})">Edit</button>
   204→          </div>
   205→        </div>
   206→      `).join('');
   207→    }
   208→
   209→    async function toggleJobStatus(jobId, currentStatus) {
   210→      const newStatus = currentStatus === 'active' ? 'paused' : 'active';
   211→      try {
   212→        await apiCall(`/recruiter/jobs/${jobId}`, {
   213→          method: 'PUT',
   214→          body: JSON.stringify({ status: newStatus })
   215→        });
   216→        loadJobs();
   217→      } catch (err) {
