   184→          <label for="interview-duration">Duration</label>
   185→          <select id="interview-duration">
   186→            <option value="30">30 minutes</option>
   187→            <option value="45">45 minutes</option>
   188→            <option value="60" selected>1 hour</option>
   189→            <option value="90">1.5 hours</option>
