   404→    async function scheduleInterview(e) {
   405→      e.preventDefault();
   406→      const applicationId = document.getElementById('candidate-select').value;
   407→      const type = document.getElementById('interview-type').value;
   408→      const date = document.getElementById('interview-date').value;
   409→      const time = document.getElementById('interview-time').value;
   410→      const duration = document.getElementById('interview-duration').value;
   411→      const notes = document.getElementById('interview-notes').value;
   412→
   413→      const scheduledAt = new Date(`${date}T${time}`);
   414→
   415→      try {
   416→        const result = await apiCall('/recruiter/interviews', {
   417→          method: 'POST',
   418→          body: JSON.stringify({
   419→            application_id: applicationId,
   420→            interview_type: type,
   421→            scheduled_at: scheduledAt.toISOString(),
   422→            duration: parseInt(duration),
   423→            notes
   424→          })
   425→        });
   426→
   427→        if (result.success) {
   428→          closeScheduleModal();
   429→          loadInterviews();
   430→        } else {
   431→          alert(result.error || 'Failed to schedule interview');
   432→        }
   433→      } catch (err) {
   434→        alert('Failed to schedule interview');
   435→      }
   436→    }
   437→
   438→    function joinInterview(id) {
   439→      // Find the interview to get meeting link
   440→      const interview = interviews.find(i => i.id == id);
   441→      if (!interview) {
   442→        alert('Interview not found');
   443→        return;
   444→      }
   445→
   446→      // If meeting link exists, open it
   447→      if (interview.meeting_link) {
   448→        window.open(interview.meeting_link, '_blank');
   449→        return;
   450→      }
   451→
   452→      // Generate a Jitsi Meet room based on interview ID
   453→      const roomName = `HireLoop-Interview-${id}-${Date.now().toString(36)}`;
   454→      const meetingLink = `https://meet.jit.si/${roomName}`;
   455→
   456→      // Update the interview with the meeting link
   457→      updateMeetingLink(id, meetingLink).then(() => {
   458→        window.open(meetingLink, '_blank');
   459→      });
   460→    }
   461→
   462→    async function updateMeetingLink(interviewId, meetingLink) {
   463→      try {
   464→        await apiCall(`/recruiter/interviews/${interviewId}`, {
   465→          method: 'PUT',
   466→          body: JSON.stringify({ meeting_link: meetingLink })
   467→        });
   468→        // Refresh to show the link
   469→        loadInterviews();
   470→      } catch (err) {
   471→        console.error('Failed to save meeting link:', err);
   472→      }
   473→    }
   474→
   475→    function reschedule(id) {
   476→      showScheduleModal();
   477→    }
   478→
   479→    async function markCompleted(id) {
   480→      try {
   481→        const result = await apiCall(`/recruiter/interviews/${id}`, {
   482→          method: 'PUT',
   483→          body: JSON.stringify({ status: 'completed' })
   484→        });
   485→        if (result.success) {
   486→          loadInterviews();
   487→        }
   488→      } catch (err) {
   489→        alert('Failed to update interview');
   490→      }
   491→    }
   492→
   493→    async function cancelInterview(id) {
   494→      if (!confirm('Cancel this interview?')) return;
   495→      try {
   496→        const result = await apiCall(`/recruiter/interviews/${id}`, {
   497→          method: 'DELETE'
   498→        });
   499→        if (result.success) {
   500→          loadInterviews();
   501→        }
   502→      } catch (err) {
   503→        alert('Failed to cancel interview');
   504→      }
   505→    }
   506→
   507→    function copyMeetingLink(link) {
   508→      navigator.clipboard.writeText(link).then(() => {
   509→        alert('Meeting link copied to clipboard!');
   510→      }).catch(err => {
   511→        console.error('Failed to copy:', err);
   512→        prompt('Copy this link:', link);
   513→      });
   514→    }
