   610→    function closeModal() {
   611→      document.getElementById('modal').classList.remove('active');
   612→      currentCandidateId = null;
   613→    }
   614→
   615→    function formatStatus(status) {
   616→      const statuses = {
   617→        'pending': 'Pending',
   618→        'in_progress': 'In Progress',
   619→        'completed': 'Completed'
   620→      };
   621→      return statuses[status] || 'Unknown';
   622→    }
   623→
   624→    function formatDate(dateString) {
   625→      if (!dateString) return '—';
   626→      const date = new Date(dateString);
   627→      return date.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
   628→    }
   629→
   630→    function escapeHtml(text) {
   631→      if (!text) return '';
   632→      const map = {
   633→        '&': '&amp;',
   634→        '<': '&lt;',
   635→        '>': '&gt;',
   636→        '"': '&quot;',
   637→        "'": '&#039;'
   638→      };
   639→      return text.replace(/[&<>"']/g, m => map[m]);
   640→    }
   641→
   642→    function viewDocContent(docId, docType) {
   643→      const doc = (window._currentDocs || []).find(d => d.id === docId);
   644→      if (!doc || !doc.document_content) return;
   645→
   646→      const content = typeof doc.document_content === 'string' ? JSON.parse(doc.document_content) : doc.document_content;
   647→      let bodyHtml = '';
   648→
   649→      if (content.form_type === 'I-9') {
   650→        bodyHtml = `
   651→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">Employment Eligibility Verification</p>
   652→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   653→          <p><strong>DOB:</strong> ${content.date_of_birth ? new Date(content.date_of_birth).toLocaleDateString() : ''}</p>
   654→          <p><strong>Address:</strong> ${escapeHtml(content.address || '')}, ${escapeHtml(content.city || '')}, ${escapeHtml(content.state || '')} ${escapeHtml(content.zip || '')}</p>
   655→          <p><strong>SSN:</strong> ${content.ssn_last_four}</p>
   656→          <p><strong>Employer:</strong> ${escapeHtml(content.company || '')}</p>
   657→        `;
   658→      } else if (content.form_type === 'W-4') {
   659→        bodyHtml = `
   660→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">W-4 Tax Withholding</p>
   661→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   662→          <p><strong>Address:</strong> ${escapeHtml(content.city_state_zip || '')}</p>
   663→          <p><strong>Filing Status:</strong> ${escapeHtml(content.filing_status || 'Single')}</p>
   664→        `;
   665→      } else if (content.form_type === 'Direct Deposit Authorization') {
   666→        bodyHtml = `
   667→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">Direct Deposit</p>
   668→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   669→          <p><strong>Bank:</strong> ${escapeHtml(content.bank_name || '')}</p>
   670→          <p><strong>Account Type:</strong> ${escapeHtml(content.account_type || '')}</p>
   671→        `;
   672→      } else {
   673→        bodyHtml = `<pre style="white-space: pre-wrap; font-size: 12px;">${JSON.stringify(content, null, 2)}</pre>`;
   674→      }
   675→
   676→      if (doc.signed_at) {
   677→        bodyHtml += `<hr style="margin: 12px 0;"><p style="color: #10b981; font-weight: 600;">✓ Signed on ${new Date(doc.signed_at).toLocaleString()}</p>`;
   678→        if (doc.signer_ip) bodyHtml += `<p style="font-size: 11px; color: #888;">IP: ${escapeHtml(doc.signer_ip)}</p>`;
   679→      }
   680→
   681→      const overlay = document.createElement('div');
   682→      overlay.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,0.5);z-index:2000;display:flex;align-items:center;justify-content:center;';
   683→      overlay.onclick = (e) => { if (e.target === overlay) overlay.remove(); };
   684→      overlay.innerHTML = `
   685→        <div style="background:var(--card-bg);border-radius:12px;max-width:500px;width:90%;padding:24px;max-height:80vh;overflow-y:auto;">
   686→          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">
   687→            <h3 style="font-size:16px;font-weight:600;">${escapeHtml(docType)}</h3>
   688→            <button onclick="this.closest('[style*=fixed]').remove()" style="background:none;border:none;font-size:20px;cursor:pointer;color:var(--text-muted);">✕</button>
   689→          </div>
   690→          <div style="font-size:13px;line-height:1.7;">${bodyHtml}</div>
   691→        </div>
   692→      `;
   693→      document.body.appendChild(overlay);
   694→    }
   695→
   696→    function downloadAllDocs() {
   697→      const docs = window._currentDocs || [];
   698→      docs.forEach((doc, i) => {
   699→        if (doc.document_content) {
   700→          setTimeout(() => {
   701→            window.open(`/api/onboarding/recruiter/document/${doc.id}/download`, '_blank');
   702→          }, i * 500);
   703→        }
   704→      });
   705→    }
   706→
   707→    // Modal close on click outside
   708→    document.getElementById('modal').addEventListener('click', (e) => {
   709→      if (e.target.id === 'modal') closeModal();
   710→    });
   711→
   712→    // Initialize
   713→    document.addEventListener('DOMContentLoaded', () => {
   714→      loadOnboardingDocuments();
   715→      setupUserMenu();
   716→      // Auto-refresh every 30 seconds for real-time updates
   717→      setInterval(loadOnboardingDocuments, 30000);
   718→    });
   719→  </script>
